### 四、核心实现示例

#### 4.1 WebSocket服务封装

```typescript
// src/dashboard/frontend/src/services/websocket.ts
import { ref, reactive } from 'vue'

export interface WSMessage {
  event: string
  data: any
}

export class WebSocketService {
  private ws: WebSocket | null = null
  private reconnectTimer: any = null
  private reconnectAttempts = 0
  private maxReconnectAttempts = 5

  public connected = ref(false)
  public messageHandlers = new Map<string, Set<(data: any) => void>>()

  constructor(private url: string) {}

  connect() {
    this.ws = new WebSocket(this.url)

    this.ws.onopen = () => {
      console.log('✅ WebSocket connected')
      this.connected.value = true
      this.reconnectAttempts = 0
    }

    this.ws.onmessage = (event) => {
      try {
        const message: WSMessage = JSON.parse(event.data)
        this.handleMessage(message)
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error)
      }
    }

    this.ws.onclose = () => {
      console.log('🔌 WebSocket disconnected')
      this.connected.value = false
      this.scheduleReconnect()
    }

    this.ws.onerror = (error) => {
      console.error('❌ WebSocket error:', error)
    }
  }

  private handleMessage(message: WSMessage) {
    const handlers = this.messageHandlers.get(message.event)
    if (handlers) {
      handlers.forEach(handler => handler(message.data))
    }
  }

  subscribe(event: string, handler: (data: any) => void) {
    if (!this.messageHandlers.has(event)) {
      this.messageHandlers.set(event, new Set())
    }
    this.messageHandlers.get(event)!.add(handler)

    // 返回取消订阅函数
    return () => {
      const handlers = this.messageHandlers.get(event)
      if (handlers) {
        handlers.delete(handler)
      }
    }
  }

  private scheduleReconnect() {
    if (this.reconnectAttempts < this.maxReconnectAttempts) {
      this.reconnectAttempts++
      const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), 30000)

      console.log(`🔄 Reconnecting in ${delay}ms... (attempt ${this.reconnectAttempts})`)

      this.reconnectTimer = setTimeout(() => {
        this.connect()
      }, delay)
    }
  }

  disconnect() {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer)
    }
    if (this.ws) {
      this.ws.close()
    }
  }
}

// 单例实例
let wsService: WebSocketService | null = null

export function useWebSocket() {
  if (!wsService) {
    wsService = new WebSocketService('ws://localhost:3000/api/ws')
  }
  return wsService
}
```

#### 4.2 Pinia Store - Agent状态管理

```typescript
// src/dashboard/frontend/src/stores/agent.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { useWebSocket } from '@/services/websocket'

export interface AgentState {
  id: string
  name: string
  icon: string
  status: 'idle' | 'running' | 'completed' | 'error'
  progress: number
  currentTask?: string
  startTime?: Date
  endTime?: Date
}

export const useAgentStore = defineStore('agent', () => {
  const ws = useWebSocket()

  // 状态
  const agents = ref<AgentState[]>([
    { id: 'product-manager', name: '产品经理', icon: '📊', status: 'idle', progress: 0 },
    { id: 'architect', name: '架构师', icon: '🏗️', status: 'idle', progress: 0 },
    { id: 'ui-designer', name: 'UI设计师', icon: '🎨', status: 'idle', progress: 0 },
    { id: 'frontend', name: '前端开发', icon: '💻', status: 'idle', progress: 0 },
    { id: 'backend', name: '后端开发', icon: '⚙️', status: 'idle', progress: 0 },
    { id: 'database', name: '数据库设计', icon: '🗄️', status: 'idle', progress: 0 },
    { id: 'tester', name: '测试工程师', icon: '🧪', status: 'idle', progress: 0 },
    { id: 'security', name: '安全工程师', icon: '🔒', status: 'idle', progress: 0 },
    { id: 'documenter', name: '文档工程师', icon: '📝', status: 'idle', progress: 0 },
    { id: 'assets', name: '素材设计师', icon: '🖼️', status: 'idle', progress: 0 }
  ])

  // 计算属性
  const activeAgents = computed(() =>
    agents.value.filter(a => a.status === 'running')
  )

  const completedAgents = computed(() =>
    agents.value.filter(a => a.status === 'completed')
  )

  // 操作
  function updateAgent(agentId: string, updates: Partial<AgentState>) {
    const index = agents.value.findIndex(a => a.id === agentId)
    if (index !== -1) {
      agents.value[index] = { ...agents.value[index], ...updates }
    }
  }

  function resetAllAgents() {
    agents.value.forEach(agent => {
      agent.status = 'idle'
      agent.progress = 0
      agent.currentTask = undefined
      agent.startTime = undefined
      agent.endTime = undefined
    })
  }

  // 订阅 WebSocket 事件
  function subscribeToEvents() {
    ws.subscribe('agent.status_changed', (data: any) => {
      updateAgent(data.agentId, {
        status: data.status,
        currentTask: data.task,
        progress: data.progress || 0
      })
    })

    ws.subscribe('agent.progress', (data: any) => {
      updateAgent(data.agentId, {
        progress: data.progress
      })
    })
  }

  return {
    agents,
    activeAgents,
    completedAgents,
    updateAgent,
    resetAllAgents,
    subscribeToEvents
  }
})
```

